package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withIgnoreHeaderCase(true);
        assertNotNull(result);
        assertTrue(result.getIgnoreHeaderCase());
        // Ensure original is unchanged (immutability)
        assertFalse(original.getIgnoreHeaderCase());
    }

}
